+import Foundation
+
+enum SerializedAudioError: LocalizedError, Equatable {
+    case invalidSerializedAudioData
+
+    var errorDescription: String? {
+        switch self {
+        case .invalidSerializedAudioData:
+            return "invalid serialized audio data"
+        }
+    }
+}
+
+enum ArchivedAudioCodec {
+    static func serializeRawFloat32(_ samples: [Float]) -> Data {
+        var samples = samples
+        return samples.withUnsafeBytes { Data($0) }
+    }
+
+    static func serializeWAV(_ samples: [Float]) -> Data {
+        let dataChunkSize = samples.count * MemoryLayout<Int16>.size
+        var data = Data()
+        data.reserveCapacity(44 + dataChunkSize)
+
+        data.appendASCII("RIFF")
+        data.appendUInt32LE(UInt32(36 + dataChunkSize))
+        data.appendASCII("WAVE")
+        data.appendASCII("fmt ")
+        data.appendUInt32LE(16)
+        data.appendUInt16LE(1)
+        data.appendUInt16LE(1)
+        data.appendUInt32LE(16_000)
+        data.appendUInt32LE(32_000)
+        data.appendUInt16LE(2)
+        data.appendUInt16LE(16)
+        data.appendASCII("data")
+        data.appendUInt32LE(UInt32(dataChunkSize))
+
+        for sample in samples {
+            let clamped = max(-1.0, min(1.0, Double(sample)))
+            let intSample = Int16((clamped * 32_767.0).rounded())
+            data.appendInt16LE(intSample)
+        }
+
+        return data
+    }
+
+    static func deserialize(_ data: Data) throws -> [Float] {
+        if data.starts(with: [0x52, 0x49, 0x46, 0x46]) {
+            return try deserializeWAV(data)
+        }
+
+        return try deserializeRawFloat32(data)
+    }
+
+    private static func deserializeRawFloat32(_ data: Data) throws -> [Float] {
+        guard data.count.isMultiple(of: MemoryLayout<Float>.size) else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var samples: [Float] = []
+        samples.reserveCapacity(data.count / MemoryLayout<Float>.size)
+
+        for offset in stride(from: 0, to: data.count, by: MemoryLayout<Float>.size) {
+            var sample: Float = 0
+            withUnsafeMutableBytes(of: &sample) { bytes in
+                data.copyBytes(to: bytes, from: offset..<(offset + MemoryLayout<Float>.size))
+            }
+            samples.append(sample)
+        }
+
+        return samples
+    }
+
+    private static func deserializeWAV(_ data: Data) throws -> [Float] {
+        guard data.count >= 44 else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+        guard data.starts(with: [0x52, 0x49, 0x46, 0x46]) else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+        guard String(decoding: data[8..<12], as: UTF8.self) == "WAVE" else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var audioFormatCode: UInt16?
+        var channelCount: UInt16?
+        var bitsPerSample: UInt16?
+        var sampleData: Data?
+        var offset = 12
+
+        while offset + 8 <= data.count {
+            let chunkID = String(decoding: data[offset..<(offset + 4)], as: UTF8.self)
+            let chunkSize = Int(try readUInt32LE(data, offset: offset + 4))
+            let chunkDataStart = offset + 8
+            let chunkDataEnd = chunkDataStart + chunkSize
+
+            guard chunkDataEnd <= data.count else {
+                throw SerializedAudioError.invalidSerializedAudioData
+            }
+
+            switch chunkID {
+            case "fmt ":
+                guard chunkSize >= 16 else {
+                    throw SerializedAudioError.invalidSerializedAudioData
+                }
+                audioFormatCode = try readUInt16LE(data, offset: chunkDataStart)
+                channelCount = try readUInt16LE(data, offset: chunkDataStart + 2)
+                bitsPerSample = try readUInt16LE(data, offset: chunkDataStart + 14)
+            case "data":
+                sampleData = data.subdata(in: chunkDataStart..<chunkDataEnd)
+            default:
+                break
+            }
+
+            offset = chunkDataEnd
+            if chunkSize.isMultiple(of: 2) == false {
+                offset += 1
+            }
+        }
+
+        guard
+            audioFormatCode == 1,
+            channelCount == 1,
+            bitsPerSample == 16,
+            let sampleData,
+            sampleData.count.isMultiple(of: 2)
+        else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var samples: [Float] = []
+        samples.reserveCapacity(sampleData.count / 2)
+        for offset in stride(from: 0, to: sampleData.count, by: 2) {
+            let sample = try readInt16LE(sampleData, offset: offset)
+            samples.append(Float(sample) / 32_767.0)
+        }
+
+        return samples
+    }
+
+    private static func readUInt16LE(_ data: Data, offset: Int) throws -> UInt16 {
+        guard offset + 2 <= data.count else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var value: UInt16 = 0
+        withUnsafeMutableBytes(of: &value) { bytes in
+            data.copyBytes(to: bytes, from: offset..<(offset + 2))
+        }
+        return UInt16(littleEndian: value)
+    }
+
+    private static func readUInt32LE(_ data: Data, offset: Int) throws -> UInt32 {
+        guard offset + 4 <= data.count else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var value: UInt32 = 0
+        withUnsafeMutableBytes(of: &value) { bytes in
+            data.copyBytes(to: bytes, from: offset..<(offset + 4))
+        }
+        return UInt32(littleEndian: value)
+    }
+
+    private static func readInt16LE(_ data: Data, offset: Int) throws -> Int16 {
+        guard offset + 2 <= data.count else {
+            throw SerializedAudioError.invalidSerializedAudioData
+        }
+
+        var value: Int16 = 0
+        withUnsafeMutableBytes(of: &value) { bytes in
+            data.copyBytes(to: bytes, from: offset..<(offset + 2))
+        }
+        return Int16(littleEndian: value)
+    }
+}
+
+private extension Data {
+    mutating func appendASCII(_ string: String) {
+        append(string.data(using: .ascii)!)
+    }
+
+    mutating func appendUInt16LE(_ value: UInt16) {
+        var littleEndian = value.littleEndian
+        Swift.withUnsafeBytes(of: &littleEndian) { bytes in
+            append(contentsOf: bytes)
+        }
+    }
+
+    mutating func appendUInt32LE(_ value: UInt32) {
+        var littleEndian = value.littleEndian
+        Swift.withUnsafeBytes(of: &littleEndian) { bytes in
+            append(contentsOf: bytes)
+        }
+    }
+
+    mutating func appendInt16LE(_ value: Int16) {
+        var littleEndian = value.littleEndian
+        Swift.withUnsafeBytes(of: &littleEndian) { bytes in
+            append(contentsOf: bytes)
+        }
+    }
+}

