+    private func prunePersistedEntriesIfNeeded() {
+        guard fileManager.fileExists(atPath: url.path()) else {
+            return
+        }
+
+        do {
+            let data = try Data(contentsOf: url)
+            var entries = try decoder.decode([DebugLogEntry].self, from: data)
+            guard entries.count > capacity else {
+                return
+            }
+
+            entries.removeFirst(entries.count - capacity)
+            try fileManager.createDirectory(
+                at: url.deletingLastPathComponent(),
+                withIntermediateDirectories: true
+            )
+            let trimmedData = try encoder.encode(entries)
+            try trimmedData.write(to: url, options: .atomic)
+        } catch {
+        }
+    }
 }

